// // This module performs a NOR operation on in1 and in2 when the reset is low, and updates out2 with the OR of in1 and in3 on each clock cycle.
module top_module(
    input in1,
    input in2,
    input in3,
    input clk,
    input reset,
    output out1,
    output out2
);reg out1_reg;
    reg out2_reg;

    always @(posedge clk) begin
        if (reset) begin
            out1_reg <= 1'b0;
            out2_reg <= 1'b0;
        end else begin
            out1_reg <= in1 ^ in2;
            out2_reg <= in2 & in3;
        end
    end

    assign out1 = out1_reg;
    assign out2 = out2_reg;

endmodule
